declare i32 @llvm.cttz.i32(i32, i1 immarg)

define i32 @test(i32 %x) {
  %cmp = icmp eq i32 %x, 0
  %cttz = call noundef i32 @llvm.cttz.i32(i32 %x, i1 true)
  %res = select i1 %cmp, i32 32, i32 %cttz
  ret i32 %res
}

