```llvm
declare { i8, i1 } @llvm.umul.with.overflow.i8(i8, i8)

define i1 @test(i8 %a, i8 %b) {
entry:
  %0 = call { i8, i1 } @llvm.umul.with.overflow.i8(i8 %a, i8 %b)
