  %neg_x = sub <2 x i8> <i8 0, i8 poison>, %x
  %sel = select <2 x i1> %cond, <2 x i8> %neg_x, <2 x i8> %x
  %res = sub <2 x i8> zeroinitializer, %sel
  ret <2 x i8> %res
}
